queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?frequent_flyer_lounges a :Frequent_Flyer_Lounges .
    ?frequent_flyer_lounges p:name ?name .
    ?frequent_flyer_lounges p:Amenities ?amenities_f .
    FILTER(STR(?amenities_f) = "Complimentary Wi-Fi")
    BIND(?name AS ?o0)
  }
  UNION
  {
    ?vip_lounges a :VIPLounges .
    ?vip_lounges p:name ?name .
    ?vip_lounges p:Amenities ?amenities_f .
    FILTER(STR(?amenities_f) = "Complimentary Wi-Fi")
    BIND(?name AS ?o0)
  }
}

